from flask import Flask, redirect, request, session, url_for
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Configuration
CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://provider.com/auth'
JWKS_URI = 'https://provider.com/.well-known/jwks.json'

def get_jwks():
    response = requests.get(JWKS_URI)
    return response.json()

@app.route('/')
def home():
    if 'id_token' in session:
        return 'Logged in with ID Token: {}'.format(session['id_token'])
    return redirect(url_for('login'))

@app.route('/login')
def login():
    authorization_url = (
        f"{AUTHORIZATION_ENDPOINT}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}"
        f"&scope=openid&response_type=id_token"
    )
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    jwks = get_jwks()
    id_token_header = jwt.get_unverified_header(id_token)
    rsa_key = next(key for key in jwks['keys'] if key['kid'] == id_token_header['kid'])
    
    try:
        decoded_token = jwt.decode(
            id_token,
            rsa_key,
            algorithms=['RS256'],
            audience=CLIENT_ID,
            options={"verify_exp": True}
        )
        session['id_token'] = id_token
        return redirect(url_for('home'))
    except jwt.ExpiredSignatureError:
        return 'Token expired, please log in again.'
    except jwt.InvalidTokenError:
        return 'Invalid token, please try again.'

if __name__ == '__main__':
    app.run(debug=True)